import React, { useState, useEffect } from 'react';
import { solveQuestion } from './services/geminiService';
import { HistoryItem, SolutionResponse } from './types';
import { InputSection } from './components/InputSection';
import { AnswerSection } from './components/AnswerSection';
import { HistorySidebar } from './components/HistorySidebar';
import { Menu, GraduationCap, Github, Sparkles } from 'lucide-react';

const App: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [currentQuestion, setCurrentQuestion] = useState<string>("");
  const [solution, setSolution] = useState<SolutionResponse | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Load history from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('sqs_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history", e);
      }
    }
  }, []);

  // Save history to local storage whenever it changes
  useEffect(() => {
    localStorage.setItem('sqs_history', JSON.stringify(history));
  }, [history]);

  const handleSolve = async (text: string, image: File | null, audio: Blob | null) => {
    setLoading(true);
    setSolution(null);
    setCurrentQuestion(text || (audio ? "Audio Question" : "Image Question"));

    try {
      const result = await solveQuestion(text, image, audio);
      setSolution(result);

      // Add to history
      const newHistoryItem: HistoryItem = {
        id: Date.now().toString(),
        question: text || (audio ? "Audio Question" : (image ? "Image Question" : "Unknown Question")),
        timestamp: Date.now(),
        solution: result,
      };

      setHistory((prev) => [newHistoryItem, ...prev].slice(0, 50)); // Keep last 50
    } catch (error) {
      console.error(error);
      alert("Failed to solve the question. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setSolution(item.solution);
    setCurrentQuestion(item.question);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen relative overflow-hidden">

      {/* Decorative background blobs */}
      <div className="fixed top-0 left-0 w-full h-full overflow-hidden -z-10 pointer-events-none">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-purple-200/30 rounded-full blur-3xl animate-pulse"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-indigo-200/30 rounded-full blur-3xl animate-pulse delay-700"></div>
      </div>

      {/* Navbar */}
      <header className="sticky top-0 z-30 bg-white/70 backdrop-blur-lg border-b border-white/20 shadow-sm transition-all duration-300">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <button 
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              className="p-2 -ml-2 text-slate-600 hover:text-indigo-600 hover:bg-white/50 rounded-xl transition-all duration-200"
            >
              <Menu size={24} />
            </button>
            <div className="flex items-center space-x-2 group cursor-pointer">
              <div className="relative">
                <div className="absolute inset-0 bg-indigo-500 rounded-lg blur opacity-20 group-hover:opacity-40 transition-opacity"></div>
                <div className="relative bg-gradient-to-br from-indigo-500 to-violet-600 text-white p-1.5 rounded-lg shadow-sm">
                   <GraduationCap size={24} />
                </div>
              </div>
              <h1 className="text-xl font-bold tracking-tight text-slate-800 hidden sm:block group-hover:text-indigo-700 transition-colors">
                Question<span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-600 to-violet-600">Solver</span>
              </h1>
            </div>
          </div>
          <div className="flex items-center space-x-4">
            <a href="#" className="text-slate-400 hover:text-indigo-600 transition-colors transform hover:scale-110 duration-200">
              <Github size={22} />
            </a>
          </div>
        </div>
      </header>

      {/* Main Layout */}
      <div className="flex">

        {/* Sidebar */}
        <HistorySidebar 
          history={history} 
          isOpen={isSidebarOpen} 
          onClose={() => setIsSidebarOpen(false)} 
          onSelect={handleSelectHistory}
        />

        {/* Content */}
        <main className={`flex-1 transition-all duration-300 ${isSidebarOpen ? 'md:ml-72' : ''} p-4 sm:p-6 lg:p-8 max-w-5xl mx-auto w-full`}>

          <div className="space-y-10 pb-20">
            {/* Hero Text */}
            {!solution && !loading && (
              <div className="text-center py-16 space-y-6 animate-fade-in-up">
                <div className="inline-flex items-center px-4 py-2 rounded-full bg-indigo-50 border border-indigo-100 text-indigo-700 text-sm font-medium mb-4 shadow-sm">
                  <Sparkles size={16} className="mr-2 text-indigo-500" />
                  AI-Powered Study Companion
                </div>
                <h2 className="text-5xl md:text-6xl font-extrabold text-slate-900 tracking-tight leading-tight">
                  Master any subject <br/>
                  <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-600 via-violet-600 to-fuchsia-600 animate-gradient-x">
                    in seconds.
                  </span>
                </h2>
                <p className="text-xl text-slate-600 max-w-2xl mx-auto leading-relaxed">
                  Upload a photo, record your voice, or type a question. 
                  Get step-by-step explanations, visual diagrams, and handwriting notes instantly.
                </p>
              </div>
            )}

            {/* Input Section */}
            <div className={`${solution ? '' : 'transform hover:-translate-y-1 transition-transform duration-300'}`}>
               <InputSection onSolve={handleSolve} isLoading={loading} />
            </div>

            {/* Results Section */}
            {solution && (
              <div className="animate-fade-in-up">
                 <AnswerSection solution={solution} />
              </div>
            )}

          </div>

        </main>
      </div>
    </div>
  );
};

