import React, { useRef, useState, useEffect } from 'react';
import { Camera, Mic, Image as ImageIcon, Send, X, StopCircle, Trash2, Sparkles } from 'lucide-react';
import { useAudioRecorder } from '../hooks/useAudioRecorder';

interface InputSectionProps {
  onSolve: (text: string, image: File | null, audio: Blob | null) => void;
  isLoading: boolean;
}

export const InputSection: React.FC<InputSectionProps> = ({ onSolve, isLoading }) => {
  const [text, setText] = useState('');
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { isRecording, audioBlob, startRecording, stopRecording, clearAudio } = useAudioRecorder();
  const [isFocused, setIsFocused] = useState(false);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedImage(e.target.files[0]);
    }
  };

  const removeImage = () => {
    setSelectedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!text && !selectedImage && !audioBlob) return;
    onSolve(text, selectedImage, audioBlob);
  };

  return (
    <div className={`
      relative bg-white rounded-2xl p-6 w-full max-w-3xl mx-auto transition-all duration-300
      border border-slate-100
      ${isFocused ? 'shadow-2xl shadow-indigo-500/10 ring-2 ring-indigo-500/20' : 'shadow-xl shadow-slate-200/50 hover:shadow-2xl hover:shadow-indigo-500/5'}
    `}>
      <form onSubmit={handleSubmit} className="space-y-4">

        {/* Text Input */}
        <div className="relative group">
          <textarea
            value={text}
            onChange={(e) => setText(e.target.value)}
            onFocus={() => setIsFocused(true)}
            onBlur={() => setIsFocused(false)}
            placeholder="Type your question here, or use voice/camera..."
            className="w-full p-4 text-lg bg-slate-50/50 border-0 rounded-xl focus:ring-0 text-slate-700 placeholder-slate-400 resize-none transition-all"
            style={{ minHeight: '100px' }}
            disabled={isLoading}
          />
          {/* Subtle line indicator */}
          <div className={`absolute bottom-0 left-0 h-0.5 bg-gradient-to-r from-indigo-500 to-violet-500 transition-all duration-300 ${isFocused ? 'w-full' : 'w-0'}`}></div>
        </div>

        {/* Attachments Preview */}
        {(selectedImage || audioBlob) && (
            <div className="flex flex-wrap gap-3 animate-fade-in-up">
                {selectedImage && (
                    <div className="relative group inline-block">
                        <div className="flex items-center space-x-2 bg-indigo-50 px-3 py-1.5 rounded-lg border border-indigo-100 shadow-sm">
                            <ImageIcon size={16} className="text-indigo-600"/>
                            <span className="text-sm text-indigo-700 truncate max-w-[150px] font-medium">{selectedImage.name}</span>
                        </div>
                        <button 
                            type="button" 
                            onClick={removeImage}
                            className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-md hover:bg-red-600 transition-all transform hover:scale-110"
                        >
                            <X size={12} />
                        </button>
                    </div>
                )}
                {audioBlob && (
                    <div className="relative group inline-block">
                         <div className="flex items-center space-x-2 bg-pink-50 px-3 py-1.5 rounded-lg border border-pink-100 shadow-sm">
                            <Mic size={16} className="text-pink-600"/>
                            <span className="text-sm text-pink-700 font-medium">Voice Recording</span>
                        </div>
                        <button 
                            type="button" 
                            onClick={clearAudio}
                            className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-md hover:bg-red-600 transition-all transform hover:scale-110"
                        >
                            <X size={12} />
                        </button>
                    </div>
                )}
            </div>
        )}

        {/* Controls */}
        <div className="flex items-center justify-between pt-2">
          <div className="flex items-center space-x-2">

            {/* Image Upload Button */}
            <button
              type="button"
              onClick={() => fileInputRef.current?.click()}
              className="p-3 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all duration-200 group relative overflow-hidden"
              title="Upload Image"
              disabled={isLoading}
            >
              <div className="absolute inset-0 bg-indigo-100 transform scale-0 group-hover:scale-100 transition-transform duration-200 rounded-xl origin-center"></div>
              <Camera size={22} className="relative z-10" />
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                className="hidden"
                onChange={handleImageUpload}
              />
            </button>

            {/* Voice Record Button */}
            <button
              type="button"
              onClick={isRecording ? stopRecording : startRecording}
              className={`p-3 rounded-xl transition-all duration-300 flex items-center space-x-2 relative overflow-hidden ${
                isRecording 
                  ? 'bg-red-50 text-red-600 ring-2 ring-red-100' 
                  : 'text-slate-500 hover:text-pink-600 hover:bg-pink-50'
              }`}
              title={isRecording ? "Stop Recording" : "Record Voice"}
              disabled={isLoading}
            >
               {isRecording && <span className="absolute inset-0 bg-red-100 animate-ping opacity-75 rounded-xl"></span>}
              <div className="relative z-10">
                  {isRecording ? <StopCircle size={22} /> : <Mic size={22} />}
              </div>
            </button>
          </div>

          {/* Submit Button */}
          <button
            type="submit"
            disabled={isLoading || (!text && !selectedImage && !audioBlob)}
            className={`
              flex items-center space-x-2 px-8 py-3 rounded-xl font-bold text-white transition-all duration-300 shadow-lg
              ${isLoading || (!text && !selectedImage && !audioBlob)
                ? 'bg-slate-300 cursor-not-allowed shadow-none'
                : 'bg-gradient-to-r from-indigo-600 to-violet-600 hover:from-indigo-500 hover:to-violet-500 hover:shadow-indigo-500/30 hover:-translate-y-0.5 active:scale-95'
              }
            `}
          >
            {isLoading ? (
               <>
                 <svg className="animate-spin -ml-1 mr-2 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                   <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                   <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                 </svg>
                 <span>Thinking...</span>
               </>
            ) : (
               <>
                 <span>Solve Question</span>
                 <Sparkles size={18} />
               </>
            )}
          </button>
        </div>
      </form>
    </div>
  );
};

