import React, { useState, useRef } from 'react';
import { SolutionResponse, AnswerMode } from '../types';
import { MermaidDiagram } from './MermaidDiagram';
import { BookOpen, List, Image as ImageIcon, Zap, FileText, Download, PenTool, Maximize2, Layers, Grid, ZoomIn, ZoomOut, RotateCcw, Save } from 'lucide-react';
import ReactMarkdown, { Components } from 'react-markdown';

declare global {
  interface Window {
    html2pdf: any;
  }
}

interface AnswerSectionProps {
  solution: SolutionResponse;
}

export const AnswerSection: React.FC<AnswerSectionProps> = ({ solution }) => {
  const [activeTab, setActiveTab] = useState<AnswerMode>(AnswerMode.SIMPLE);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  // Visual Section State
  const [zoomLevel, setZoomLevel] = useState(1);
  const visualContainerRef = useRef<HTMLDivElement>(null);

  const tabs = [
    { id: AnswerMode.SIMPLE, label: 'Simple', icon: <BookOpen size={18} />, color: 'bg-blue-100 text-blue-700' },
    { id: AnswerMode.STEP_BY_STEP, label: 'Steps', icon: <List size={18} />, color: 'bg-emerald-100 text-emerald-700' },
    { id: AnswerMode.HANDWRITTEN, label: 'Notes', icon: <PenTool size={18} />, color: 'bg-amber-100 text-amber-700' },
    { id: AnswerMode.VISUAL, label: 'Visual', icon: <ImageIcon size={18} />, color: 'bg-violet-100 text-violet-700' },
    { id: AnswerMode.SHORT, label: 'Short', icon: <Zap size={18} />, color: 'bg-orange-100 text-orange-700' },
    { id: AnswerMode.DETAILED, label: 'Detailed', icon: <FileText size={18} />, color: 'bg-indigo-100 text-indigo-700' },
  ];

  const handleDownloadPDF = async () => {
    setIsGeneratingPdf(true);
    const element = document.getElementById('answer-content-export');

    if (element && window.html2pdf) {
      const opt = {
        margin: [0.5, 0.5],
        filename: `${solution.subject.replace(/\s+/g, '_')}_Solution.pdf`,
        image: { type: 'jpeg', quality: 0.98 },
        html2canvas: { scale: 2, useCORS: true },
        jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
      };

      try {
        await window.html2pdf().set(opt).from(element).save();
      } catch (e) {
        console.error("PDF generation failed", e);
        // Fallback to browser print
        window.print();
      }
    } else {
       // Fallback if lib not loaded
       window.print();
    }
    setIsGeneratingPdf(false);
  };

  const handleZoom = (direction: 'in' | 'out') => {
    setZoomLevel(prev => {
        const newZoom = direction === 'in' ? prev + 0.2 : prev - 0.2;
        return Math.min(Math.max(newZoom, 0.5), 3); // Limit zoom between 0.5x and 3x
    });
  };

  const handleResetZoom = () => setZoomLevel(1);

  const handleDownloadDiagram = () => {
    const svg = visualContainerRef.current?.querySelector('svg');
    if (svg) {
        const svgData = new XMLSerializer().serializeToString(svg);
        const blob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `${solution.subject}_Diagram.svg`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
