                            <Mic size={18} className="text-pink-600"/>
                            <span className="text-sm text-pink-700 font-medium">Voice Recording Attached</span>
                        </div>
                        <button 
                            type="button" 
                            onClick={(e) => { e.stopPropagation(); clearAudio(); }}
                            className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-md hover:bg-red-600 transition-all transform hover:scale-110"
                        >
                            <X size={12} />
                        </button>
                    </div>
                )}
            </div>
        )}

