export type Language = 'en' | 'ur';

export enum AnswerMode {
  SIMPLE = 'simple',
  STEP_BY_STEP = 'stepByStep',
  VISUAL = 'visual',
  SHORT = 'short',
  DETAILED = 'detailed',
  HANDWRITTEN = 'handwritten',
}

export interface SolutionResponse {
  simple: string;
  stepByStep: string;
  visual: string; // Mermaid diagram code
  short: string;
  detailed: string;
  handwrittenNotes: string;
  subject: string;
}

export interface HistoryItem {
  id: string;
  question: string;
  timestamp: number;
  solution: SolutionResponse;
}

export interface QuestionInput {
  text: string;
  image?: File | null;
  audio?: Blob | null;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { SolutionResponse, Language } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    simple: {
      type: Type.STRING,
      description: "A simple, easy-to-understand explanation (3-4 lines).",
    },
    stepByStep: {
      type: Type.STRING,
      description: "A detailed step-by-step breakdown using Markdown formatting.",
    },
    visual: {
      type: Type.STRING,
      description: "Mermaid.js diagram syntax (e.g., flowchart TD, graph LR). IMPORTANT: Enclose ALL node labels in double quotes to handle parentheses/special characters safely (e.g., A[\"Label (Info)\"]). Do not use markdown code blocks.",
    },
    short: {
      type: Type.STRING,
      description: "A very short 1-2 line summary.",
    },
    detailed: {
      type: Type.STRING,
      description: "A comprehensive explanation with concepts, reasoning, and context using Markdown.",
    },
    handwrittenNotes: {
      type: Type.STRING,
      description: "Notes formatted like a student's notebook. Use arrows (->), bullet points, colloquial simplifications, and emphasize keywords. Make it look like 'cheat sheet' notes.",
    },
    subject: {
      type: Type.STRING,
      description: "The detected subject of the question (e.g., Physics, History).",
    },
  },
  required: ["simple", "stepByStep", "visual", "short", "detailed", "handwrittenNotes", "subject"],
};

export const solveQuestion = async (
  text: string,
  imageFile: File | null,
  audioBlob: Blob | null,
  language: Language
): Promise<SolutionResponse> => {
  const parts: any[] = [];

  const langName = language === 'ur' ? 'Urdu' : 'English';

  // Add system instruction as part of the prompt context since we want specific formatting
  const prompt = `
    You are an expert tutor for students. 
    Analyze the following question and provide a comprehensive answer in the requested JSON format.

    IMPORTANT INSTRUCTION: Provide ALL text content (explanations, notes, steps) in ${langName}. 
    For the 'subject' field, provide the subject name in ${langName}.

    For the 'visual' field:
    1. Create a valid Mermaid.js diagram (flowchart or sequence) that simplifies the concept.
    2. CRITICAL: Enclose all node labels in double quotes. Example: id["Label (with info)"] is correct. id[Label (with info)] is WRONG.
    3. Ensure node labels are translated to ${langName} where appropriate, but keep the IDs simple (ASCII).
    4. Do not include markdown code fences (\`\`\`mermaid).

    For the 'handwrittenNotes' field:
    1. Write as if taking quick, smart notes for an exam in ${langName}.
    2. Use symbols like "->" for "leads to", "&" for "and".
    3. Keep bullet points short and punchy.

    Question: ${text}
  `;

  parts.push({ text: prompt });

  if (imageFile) {
    const base64Image = await fileToBase64(imageFile);
    parts.push({
      inlineData: {
        mimeType: imageFile.type,
        data: base64Image,
      },
    });
  }

  if (audioBlob) {
    const base64Audio = await blobToBase64(audioBlob);
    parts.push({
      inlineData: {
        mimeType: "audio/mp3", // Assuming the blob is recorded as mp3 or wav, Gemini is flexible but mime type helps
        data: base64Audio,
      },
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        systemInstruction: `You are a helpful, encouraging, and accurate academic tutor. You MUST answer in ${langName}.`,
      },
    });

    const responseText = response.text;
    if (!responseText) throw new Error("No response from AI");

    return JSON.parse(responseText) as SolutionResponse;
  } catch (error) {
    console.error("Error solving question:", error);
    throw error;
  }
};

// Helper functions
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(",")[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      const base64 = result.split(",")[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

import React, { useRef, useState } from 'react';
import { Camera, Mic, Image as ImageIcon, X, StopCircle, Sparkles, ArrowRight } from 'lucide-react';
import { useAudioRecorder } from '../hooks/useAudioRecorder';
import { Language } from '../types';

interface InputSectionProps {
  onSolve: (text: string, image: File | null, audio: Blob | null) => void;
  isLoading: boolean;
  language: Language;
}

export const InputSection: React.FC<InputSectionProps> = ({ onSolve, isLoading, language }) => {
  const [text, setText] = useState('');
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const { isRecording, audioBlob, startRecording, stopRecording, clearAudio } = useAudioRecorder();
  const [isFocused, setIsFocused] = useState(false);

  const isUrdu = language === 'ur';
  const placeholder = isUrdu 
    ? "اپنا سوال یہاں لکھیں، یا آواز/کیمرہ استعمال کریں..." 
    : "Type your question here, or use voice/camera...";

  const solveText = isUrdu ? "حل کریں" : "Solve";
  const solvingText = isUrdu ? "...حل ہو رہا ہے" : "Solving...";
  const recordingText = isUrdu ? "رکارڈنگ ہو رہی ہے" : "Recording...";
  const imageAttachedText = isUrdu ? "تصویر منسلک ہے" : "Image Attached";
  const audioAttachedText = isUrdu ? "آواز ریکارڈ ہو گئی" : "Voice Recording Attached";

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedImage(e.target.files[0]);
    }
  };

  const removeImage = () => {
    setSelectedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!text && !selectedImage && !audioBlob) return;
    onSolve(text, selectedImage, audioBlob);
  };

  const handleContainerClick = (e: React.MouseEvent) => {
    // Prevent focusing if clicking on buttons/controls
    if ((e.target as HTMLElement).tagName === 'BUTTON' || (e.target as HTMLElement).closest('button')) {
      return;
    }
    textareaRef.current?.focus();
  };

  return (
    <div 
      dir={isUrdu ? 'rtl' : 'ltr'}
      className={`
      relative bg-white rounded-2xl p-6 w-full max-w-3xl mx-auto transition-all duration-300 cursor-text
      border border-slate-200 no-print
      ${isFocused ? 'shadow-2xl shadow-indigo-500/15 ring-2 ring-indigo-500' : 'shadow-xl shadow-slate-200/50 hover:shadow-2xl hover:shadow-indigo-500/5 hover:border-indigo-200'}
    `}>
      <form onSubmit={handleSubmit} className="space-y-4">

        {/* Text Input */}
        <div className="relative group">
          <textarea
            ref={textareaRef}
            value={text}
            onChange={(e) => setText(e.target.value)}
            onFocus={() => setIsFocused(true)}
            onBlur={() => setIsFocused(false)}
            placeholder={placeholder}
            className={`w-full p-0 text-lg bg-transparent border-0 focus:ring-0 text-slate-800 placeholder-slate-400 resize-none leading-relaxed ${isUrdu ? 'font-[sans-serif]' : ''}`}
            style={{ minHeight: '120px' }}
            disabled={isLoading}
          />
        </div>

        {/* Attachments Preview */}
        {(selectedImage || audioBlob) && (
            <div className="flex flex-wrap gap-3 animate-fade-in-up py-2 border-t border-slate-100">
                {selectedImage && (
                    <div className="relative group inline-block">
                        <div className="flex items-center space-x-2 bg-indigo-50 px-3 py-2 rounded-lg border border-indigo-100 shadow-sm">
                            <ImageIcon size={18} className="text-indigo-600"/>
                            <span className="text-sm text-indigo-700 truncate max-w-[150px] font-medium">
                              {selectedImage.name || imageAttachedText}
                            </span>
                        </div>
                        <button 
                            type="button" 
                            onClick={(e) => { e.stopPropagation(); removeImage(); }}
                            className={`absolute -top-2 bg-red-500 text-white rounded-full p-1 shadow-md hover:bg-red-600 transition-all transform hover:scale-110 ${isUrdu ? '-left-2' : '-right-2'}`}
                        >
                            <X size={12} />
                        </button>
                    </div>
                )}
                {audioBlob && (
                    <div className="relative group inline-block">
                         <div className="flex items-center space-x-2 bg-pink-50 px-3 py-2 rounded-lg border border-pink-100 shadow-sm">
                            <Mic size={18} className="text-pink-600"/>
                            <span className="text-sm text-pink-700 font-medium">{audioAttachedText}</span>
                        </div>
                        <button 
                            type="button" 
                            onClick={(e) => { e.stopPropagation(); clearAudio(); }}
                            className={`absolute -top-2 bg-red-500 text-white rounded-full p-1 shadow-md hover:bg-red-600 transition-all transform hover:scale-110 ${isUrdu ? '-left-2' : '-right-2'}`}
                        >
                            <X size={12} />
                        </button>
                    </div>
                )}
            </div>
        )}

        {/* Controls */}
        <div className="flex items-center justify-between pt-2 border-t border-slate-100 mt-2">
          <div className="flex items-center space-x-2">

            {/* Image Upload Button */}
            <button
              type="button"
              onClick={(e) => { e.stopPropagation(); fileInputRef.current?.click(); }}
              className="p-3 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all duration-200 group relative overflow-hidden"
              title={isUrdu ? "تصویر اپ لوڈ کریں" : "Upload Image"}
              disabled={isLoading}
            >
              <div className="absolute inset-0 bg-indigo-100 transform scale-0 group-hover:scale-100 transition-transform duration-200 rounded-xl origin-center"></div>
              <Camera size={22} className="relative z-10" />
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                className="hidden"
                onChange={handleImageUpload}
              />
            </button>

            {/* Voice Record Button */}
            <button
              type="button"
              onClick={(e) => { e.stopPropagation(); isRecording ? stopRecording() : startRecording(); }}
              className={`p-3 rounded-xl transition-all duration-300 flex items-center space-x-2 relative overflow-hidden ${
                isRecording 
                  ? 'bg-red-50 text-red-600 ring-2 ring-red-100 animate-pulse' 
                  : 'text-slate-500 hover:text-pink-600 hover:bg-pink-50'
              }`}
              title={isRecording ? (isUrdu ? "ریکارڈنگ روکیں" : "Stop Recording") : (isUrdu ? "آواز ریکارڈ کریں" : "Record Voice")}
              disabled={isLoading}
            >
              <div className="relative z-10">
                  {isRecording ? <StopCircle size={22} /> : <Mic size={22} />}
              </div>
            </button>
          </div>

          {/* Submit Button */}
          <button
            type="submit"
            onClick={(e) => e.stopPropagation()}
            disabled={isLoading || (!text && !selectedImage && !audioBlob)}
            className={`
              flex items-center space-x-2 px-6 py-3 rounded-xl font-bold text-white transition-all duration-300 shadow-lg
              ${isLoading || (!text && !selectedImage && !audioBlob)
                ? 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none'
                : 'bg-gradient-to-r from-indigo-600 to-violet-600 hover:from-indigo-500 hover:to-violet-500 hover:shadow-indigo-500/30 hover:-translate-y-0.5 active:scale-95'
              }
            `}
          >
            {isLoading ? (
               <>
                 <svg className="animate-spin -ml-1 mr-2 h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                   <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                   <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                 </svg>
                 <span>{solvingText}</span>
               </>
            ) : (
               <>
                 <span className={`${isUrdu ? 'ml-2' : ''} hidden sm:inline`}>{solveText}</span>
                 {(!text && !selectedImage && !audioBlob) ? <Sparkles size={18} /> : (isUrdu ? <ArrowRight size={20} className="transform rotate-180" /> : <ArrowRight size={20} />)}
               </>
            )}
          </button>
        </div>
      </form>
    </div>
  );
};

