            <div className="flex items-center space-x-2 group cursor-pointer" onClick={() => { setSolution(null); setError(null); }}>
              <div className="relative">
                <div className="absolute inset-0 bg-indigo-500 rounded-lg blur opacity-20 group-hover:opacity-40 transition-opacity"></div>
                <div className="relative bg-gradient-to-br from-indigo-500 to-violet-600 text-white p-1.5 rounded-lg shadow-sm">
                   <GraduationCap size={24} />
