    systemDiagram: { en: 'System Diagram', ur: 'سسٹم ڈایاگرام' },
    aiGenerated: { en: 'AI Generated Visualization', ur: 'AI کی تیار کردہ تصویر' },
    diagramHelp: { en: 'Pan to explore. Diagrams are automatically generated.', ur: 'تصویر کو گھسیٹ کر دیکھیں۔ تصاویر خودکار طور پر بنتی ہیں۔' },
    copy: { en: 'Copy', ur: 'کاپی کریں' },
    copied: { en: 'Copied!', ur: 'کاپی ہو گیا!' }
  };

  const getT = (key: keyof typeof t) => t[key][language];

  // Helper to safely get content based on language
  const getContent = (field: keyof SolutionResponse) => {
    // Check if the field is bilingual object (has 'en' and 'ur') or fallback for old history
    const data = solution[field] as any;
    if (typeof data === 'string') return data; // Old history format
    return data[language] || data['en']; // New bilingual format
  };

  const handleCopy = (text: string, sectionId: string) => {
    navigator.clipboard.writeText(text);
    setCopiedSection(sectionId);
    setTimeout(() => setCopiedSection(null), 2000);
  };

  const CopyButton = ({ text, id }: { text: string, id: string }) => (
    <button 
      onClick={() => handleCopy(text, id)}
      className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all ml-2"
      title={getT('copy')}
    >
      {copiedSection === id ? <Check size={18} className="text-green-500" /> : <Copy size={18} />}
    </button>
  );

  const tabs = [
    { id: AnswerMode.SIMPLE, label: getT('simple'), icon: <BookOpen size={18} />, color: 'bg-blue-100 text-blue-700' },
    { id: AnswerMode.STEP_BY_STEP, label: getT('steps'), icon: <List size={18} />, color: 'bg-emerald-100 text-emerald-700' },
    { id: AnswerMode.HANDWRITTEN, label: getT('notes'), icon: <PenTool size={18} />, color: 'bg-amber-100 text-amber-700' },
    { id: AnswerMode.VISUAL, label: getT('visual'), icon: <ImageIcon size={18} />, color: 'bg-violet-100 text-violet-700' },
    { id: AnswerMode.SHORT, label: getT('short'), icon: <Zap size={18} />, color: 'bg-orange-100 text-orange-700' },
    { id: AnswerMode.DETAILED, label: getT('detailed'), icon: <FileText size={18} />, color: 'bg-indigo-100 text-indigo-700' },
  ];

  const handleDownloadPDF = async () => {
    setIsGeneratingPdf(true);
    const element = document.getElementById('answer-content-export');

    if (element && window.html2pdf) {
      const opt = {
        margin: [0.5, 0.5],
        filename: `${getContent('subject').replace(/\s+/g, '_')}_Solution.pdf`,
        image: { type: 'jpeg', quality: 0.98 },
        html2canvas: { scale: 2, useCORS: true },
        jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
      };

      try {
        await window.html2pdf().set(opt).from(element).save();
      } catch (e) {
        console.error("PDF generation failed", e);
        window.print();
      }
    } else {
       window.print();
    }
    setIsGeneratingPdf(false);
  };

  const handleZoom = (direction: 'in' | 'out') => {
    setZoomLevel(prev => {
        const newZoom = direction === 'in' ? prev + 0.25 : prev - 0.25;
        return Math.min(Math.max(newZoom, 0.5), 4);
    });
  };

  const handleResetZoom = () => {
    setZoomLevel(1);
    setPan({ x: 0, y: 0 });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    dragStartRef.current = { x: e.clientX - pan.x, y: e.clientY - pan.y };
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (isDragging) {
      e.preventDefault();
      setPan({
        x: e.clientX - dragStartRef.current.x,
        y: e.clientY - dragStartRef.current.y
      });
    }
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const handleDownloadDiagram = () => {
    const svg = visualContainerRef.current?.querySelector('svg');
    if (svg) {
        try {
            const svgData = new XMLSerializer().serializeToString(svg);
            const blob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
            const url = URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.download = `${getContent('subject')}_Diagram.svg`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        } catch (e) {
            console.error("Download failed", e);
        }
    }
  };

  // --- Components for Step-by-Step View ---
  const stepsComponents: any = {
    // Style numbered lists to be clean and spacious
    ol: ({node, ...props}: any) => <ol className="space-y-4 my-6 list-none p-0" {...props} />,
    ul: ({node, ...props}: any) => <ul className={`space-y-3 my-4 list-disc ${isUrdu ? 'pr-5' : 'pl-5'}`} {...props} />,

    // Each step is a "card"
    li: ({node, ...props}: any) => {
        // Simple check to distinguish top-level step items vs nested lists might not be perfect in ReactMarkdown 
        // without inspecting parents, but we style 'li' generically to look good.
        return (
            <li className="relative bg-white p-5 rounded-xl border border-emerald-100/50 shadow-[0_2px_8px_-2px_rgba(0,0,0,0.05)] hover:shadow-md transition-all text-lg leading-relaxed text-slate-700">
                {props.children}
            </li>
        );
    },
    // Headings inside steps
    h3: ({node, ...props}: any) => <h3 className="text-xl font-bold text-emerald-800 mb-3 mt-1" {...props} />,
    // Bold text highlight
    strong: ({node, ...props}: any) => <strong className="font-bold text-emerald-900 bg-emerald-100/50 px-1.5 py-0.5 rounded-md" {...props} />,
    p: ({node, ...props}: any) => <p className="mb-2 last:mb-0" {...props} />,
  };

  // --- Components for Detailed View ---
  const detailedComponents: any = {
    h1: ({node, ...props}: any) => (
        <h1 className="text-3xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-indigo-700 to-violet-700 mb-8 pb-4 border-b border-indigo-100/50" {...props} />
    ),
    h2: ({node, ...props}: any) => (
        <h2 className="text-2xl font-bold text-slate-800 mt-12 mb-6 flex items-center group" {...props}>
            <span className={`w-1.5 h-8 bg-indigo-500 rounded-full group-hover:bg-indigo-600 transition-colors shadow-sm ${isUrdu ? 'ml-4' : 'mr-4'}`}></span>
            {props.children}
        </h2>
    ),
    h3: ({node, ...props}: any) => (
        <h3 className="text-xl font-semibold text-slate-700 mt-8 mb-4 flex items-center" {...props}>
            <span className={`w-2 h-2 rounded-full bg-indigo-300 ${isUrdu ? 'ml-3' : 'mr-3'}`}></span>
            {props.children}
        </h3>
    ),
    // More line height (leading-loose) and spacing (mb-6) for "khula" look
    p: ({node, ...props}: any) => (
        <p className="text-slate-600 leading-loose mb-6 text-lg tracking-wide" {...props} />
    ),
    ul: ({node, ...props}: any) => (
        <ul className={`space-y-4 mb-8 ${isUrdu ? 'mr-4' : 'ml-4'}`} {...props} />
    ),
    ol: ({node, ...props}: any) => (
        <ol className={`list-decimal space-y-4 mb-8 text-slate-700 font-medium marker:text-indigo-600 marker:font-bold ${isUrdu ? 'mr-8' : 'ml-8'}`} {...props} />
    ),
    li: ({node, ...props}: any) => (
        <li className={`${isUrdu ? 'pr-2' : 'pl-2'} relative text-lg leading-relaxed`} {...props} />
    ),
    blockquote: ({node, ...props}: any) => (
        <div className="relative my-10 group">
            <div className="absolute -inset-0.5 bg-gradient-to-r from-indigo-500 to-purple-500 rounded-xl blur opacity-10 group-hover:opacity-20 transition duration-500"></div>
            <blockquote className={`relative p-8 bg-white/80 backdrop-blur rounded-lg ${isUrdu ? 'border-r-[6px]' : 'border-l-[6px]'} border-indigo-500 text-slate-700 shadow-sm overflow-hidden`}>
                <div className={`absolute top-[-10px] ${isUrdu ? 'left-4' : 'right-4'} text-9xl text-indigo-50 opacity-[0.08] font-serif select-none pointer-events-none`}>
                    "
                </div>
                <div className="italic font-medium leading-loose relative z-10 text-lg">
                    {props.children}
                </div>
            </blockquote>
        </div>
    ),
    code: ({node, inline, className, children, ...props}: any) => {
        if (inline) {
            return <code className="px-1.5 py-0.5 rounded-md bg-indigo-50 text-indigo-600 font-mono text-sm border border-indigo-100 font-semibold" dir="ltr" {...props}>{children}</code>;
        }
        return (
            <div className="my-8 rounded-xl overflow-hidden border border-slate-700/50 shadow-2xl bg-[#1e1e1e] group" dir="ltr">
                <div className="flex items-center justify-between px-4 py-2 bg-[#2d2d2d] border-b border-white/10">
                    <div className="flex items-center space-x-2">
                        <div className="w-3 h-3 rounded-full bg-red-500/80 group-hover:bg-red-500 transition-colors"></div>
                        <div className="w-3 h-3 rounded-full bg-yellow-500/80 group-hover:bg-yellow-500 transition-colors"></div>
                        <div className="w-3 h-3 rounded-full bg-green-500/80 group-hover:bg-green-500 transition-colors"></div>
                    </div>
                    <div className="text-[10px] uppercase font-bold text-gray-500 tracking-wider">Code Snippet</div>
                </div>
                <pre className="p-6 overflow-x-auto text-sm text-gray-300 font-mono leading-relaxed bg-[#1e1e1e]">
                    <code {...props}>{children}</code>
                </pre>
            </div>
        );
    },
    table: ({node, ...props}: any) => (
        <div className="overflow-x-auto my-10 rounded-xl border border-slate-200 shadow-sm bg-white">
            <table className="min-w-full divide-y divide-slate-200" {...props} />
        </div>
    ),
    thead: ({node, ...props}: any) => <thead className="bg-indigo-50/50" {...props} />,
    th: ({node, ...props}: any) => <th className={`px-6 py-4 text-xs font-bold text-indigo-800 uppercase tracking-wider ${isUrdu ? 'text-right' : 'text-left'}`} {...props} />,
    tbody: ({node, ...props}: any) => <tbody className="bg-white divide-y divide-slate-100" {...props} />,
    tr: ({node, ...props}: any) => <tr className="hover:bg-indigo-50/30 transition-colors" {...props} />,
    td: ({node, ...props}: any) => <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600" {...props} />,
    strong: ({node, ...props}: any) => <strong className="font-bold text-indigo-900 bg-indigo-50 px-1 rounded shadow-sm" {...props} />,
  };

  const renderContent = () => {
    switch (activeTab) {
      case AnswerMode.SIMPLE:
        const simpleText = getContent('simple');
        return (
          <div className="animate-fade-in-up">
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-slate-800 flex items-center">
                    <span className={`w-8 h-8 rounded-lg bg-blue-100 text-blue-600 flex items-center justify-center ${isUrdu ? 'ml-3' : 'mr-3'}`}>
                        <BookOpen size={18} />
                    </span>
                    {getT('simpleTitle')}
                </h3>
                <CopyButton text={simpleText} id="simple" />
            </div>
            <div className="p-6 bg-gradient-to-br from-blue-50 to-white border border-blue-100 rounded-2xl shadow-sm hover:shadow-md transition-shadow">
              <div className="text-lg text-slate-700 leading-relaxed font-medium">
                {simpleText}
              </div>
            </div>
          </div>
        );
      case AnswerMode.STEP_BY_STEP:
        const stepText = getContent('stepByStep');
        return (
          <div className="animate-fade-in-up">
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-slate-800 flex items-center">
                    <span className={`w-8 h-8 rounded-lg bg-emerald-100 text-emerald-600 flex items-center justify-center ${isUrdu ? 'ml-3' : 'mr-3'}`}>
                        <List size={18} />
                    </span>
                    {getT('stepsTitle')}
                </h3>
                <CopyButton text={stepText} id="steps" />
            </div>
            {/* Steps Container with Light Green Background */}
            <div className="bg-gradient-to-br from-emerald-50/60 to-teal-50/40 p-6 sm:p-8 rounded-3xl border border-emerald-100/50 shadow-sm hover:shadow-md transition-shadow">
                <div className="prose prose-emerald prose-lg max-w-none">
                    <ReactMarkdown components={stepsComponents}>
                        {stepText}
                    </ReactMarkdown>
                </div>
            </div>
          </div>
        );
      case AnswerMode.HANDWRITTEN:
        const notesText = getContent('handwrittenNotes');
        return (
          <div className="w-full animate-fade-in-up">
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-slate-800 flex items-center">
                    <span className={`w-8 h-8 rounded-lg bg-amber-100 text-amber-600 flex items-center justify-center ${isUrdu ? 'ml-3' : 'mr-3'}`}>
                        <PenTool size={18} />
                    </span>
                    {getT('notesTitle')}
                </h3>
                <CopyButton text={notesText} id="notes" />
            </div>
            {/* Spiral Notebook Container */}
            <div className={`notebook-paper relative p-8 pb-16 min-h-[500px] border-l-8 border-transparent shadow-xl ${isUrdu ? 'text-right' : 'text-left'}`}>
              <div className={`${isUrdu ? 'pr-12' : 'pl-12'} font-handwriting text-2xl ink-text animate-ink`} style={{ lineHeight: '2.5rem' }}>
                 <ReactMarkdown 
                    components={{
                        // Remove margins from block elements to maintain line alignment
                        ul: ({node, ...props}) => <ul className={`list-disc ${isUrdu ? 'pr-6' : 'pl-6'} mb-0`} {...props} />,
                        ol: ({node, ...props}) => <ol className={`list-decimal ${isUrdu ? 'pr-6' : 'pl-6'} mb-0`} {...props} />,
                        li: ({node, ...props}) => <li className={`${isUrdu ? 'pr-2' : 'pl-2'} mb-0`} {...props} />,
                        p: ({node, ...props}) => <p className="mb-0" {...props} />,
                        h1: ({node, ...props}) => <h1 className="text-3xl font-bold underline decoration-wavy decoration-indigo-300 mb-0 mt-0" {...props} />,
                        h2: ({node, ...props}) => <h2 className="text-2xl font-bold mb-0 mt-0" {...props} />,
                        h3: ({node, ...props}) => <h3 className="text-xl font-bold mb-0 mt-0 uppercase tracking-widest text-indigo-800/80" {...props} />,
                        strong: ({node, ...props}) => <strong className="font-bold text-indigo-900 bg-yellow-200/30 px-1 rounded transform -skew-x-6 inline-block" {...props} />,
                        em: ({node, ...props}) => <em className="text-indigo-800 decoration-2 underline decoration-indigo-200" {...props} />,
                        blockquote: ({node, ...props}) => <blockquote className={`border-l-4 border-indigo-300 ${isUrdu ? 'pr-4' : 'pl-4'} italic text-slate-600 my-0`} {...props} />,
                    }}
                 >
                    {notesText}
                 </ReactMarkdown>
              </div>
            </div>
          </div>
        );
      case AnswerMode.VISUAL:
        const visualCode = getContent('visual');
        return (
          <div className="w-full animate-fade-in-up">
             <div className="flex justify-between items-end mb-4">
                <h3 className="text-xl font-bold text-slate-800 flex items-center">
                    <span className={`w-8 h-8 rounded-lg bg-violet-100 text-violet-600 flex items-center justify-center ${isUrdu ? 'ml-3' : 'mr-3'}`}>
                        <ImageIcon size={18} />
                    </span>
                    {getT('visualTitle')}
                </h3>
             </div>

            {/* Visual Canvas Container */}
            <div dir="ltr" className="group relative rounded-2xl overflow-hidden border border-slate-200 shadow-lg bg-slate-50 transition-all duration-300 hover:shadow-xl hover:border-violet-200">
                {/* Window Header */}
                <div className="h-10 bg-white border-b border-slate-200 flex items-center px-4 justify-between z-10 relative">
                    <div className="flex items-center space-x-2">
                        <div className="w-3 h-3 rounded-full bg-red-400"></div>
                        <div className="w-3 h-3 rounded-full bg-yellow-400"></div>
                        <div className="w-3 h-3 rounded-full bg-green-400"></div>
                    </div>
                    <div className="text-xs font-semibold text-slate-400 uppercase tracking-widest flex items-center">
                        <Layers size={12} className="mr-1.5" />
                        {getT('systemDiagram')}
                    </div>
                    {/* Toolbar */}
                    <div className="flex items-center space-x-1 no-print">
                        <button onClick={() => handleZoom('out')} className="p-1.5 hover:bg-slate-100 rounded text-slate-500" title="Zoom Out">
                            <ZoomOut size={14} />
                        </button>
                        <span className="text-xs text-slate-400 min-w-[30px] text-center">{Math.round(zoomLevel * 100)}%</span>
                        <button onClick={() => handleZoom('in')} className="p-1.5 hover:bg-slate-100 rounded text-slate-500" title="Zoom In">
                            <ZoomIn size={14} />
                        </button>
                        <button onClick={handleResetZoom} className="p-1.5 hover:bg-slate-100 rounded text-slate-500" title="Reset View">
                            <RotateCcw size={14} />
                        </button>
                         <div className="w-px h-4 bg-slate-200 mx-1"></div>
                        <button onClick={handleDownloadDiagram} className="p-1.5 hover:bg-slate-100 rounded text-indigo-600" title={getT('downloadImg')}>
                            <Save size={14} />
                        </button>
                    </div>
                </div>

                {/* Canvas Area */}
                <div 
                    className={`relative h-[500px] overflow-hidden bg-[linear-gradient(to_right,#80808012_1px,transparent_1px),linear-gradient(to_bottom,#80808012_1px,transparent_1px)] bg-[size:24px_24px] ${isDragging ? 'cursor-grabbing' : 'cursor-grab'}`}
                    onMouseDown={handleMouseDown}
                    onMouseMove={handleMouseMove}
                    onMouseUp={handleMouseUp}
                    onMouseLeave={handleMouseUp}
                >
                    <div 
                        className={`w-full h-full flex items-center justify-center origin-center transition-transform ${isDragging ? 'duration-0' : 'duration-200'} ease-out`}
                        style={{ transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoomLevel})` }}
                        ref={visualContainerRef}
                    >
                         <div className="max-w-[90%] max-h-[90%] pointer-events-none select-none">
                            <MermaidDiagram code={visualCode} />
                         </div>
                    </div>
                </div>

                {/* Footer Info */}
                <div className="bg-white px-4 py-2 border-t border-slate-100 flex justify-between items-center text-xs text-slate-400 z-10 relative">
                    <div className="flex items-center">
                         <Grid size={12} className="mr-1.5" />
                         <span>Mermaid.js Renderer v10.9</span>
                    </div>
                    <span>{getT('aiGenerated')}</span>
                </div>
            </div>

             <p className="text-center text-slate-400 text-sm mt-6 no-print">
                {getT('diagramHelp')}
            </p>
          </div>
        );
      case AnswerMode.SHORT:
        const shortText = getContent('short');
        return (
          <div className="animate-fade-in-up">
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-slate-800 flex items-center">
                    <span className={`w-8 h-8 rounded-lg bg-orange-100 text-orange-600 flex items-center justify-center ${isUrdu ? 'ml-3' : 'mr-3'}`}>
                        <Zap size={18} />
                    </span>
                    {getT('shortTitle')}
                </h3>
                <CopyButton text={shortText} id="short" />
            </div>
            <div className="p-8 bg-gradient-to-r from-orange-50 to-amber-50 border-l-8 border-orange-400 rounded-xl shadow-sm">
               <p className="text-2xl font-medium text-slate-800 italic font-serif leading-normal">
                "{shortText}"
              </p>
            </div>
          </div>
        );
      case AnswerMode.DETAILED:
        const detailedText = getContent('detailed');
        return (
          <div className="animate-fade-in-up">
             <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-slate-800 flex items-center">
                    <span className={`w-8 h-8 rounded-lg bg-indigo-100 text-indigo-600 flex items-center justify-center ${isUrdu ? 'ml-3' : 'mr-3'}`}>
                        <FileText size={18} />
                    </span>
                    {getT('detailedTitle')}
                </h3>
                <CopyButton text={detailedText} id="detailed" />
             </div>
             {/* Detailed Container with Light Blue/Grey Background */}
             <div className="bg-gradient-to-br from-slate-50 to-indigo-50/30 p-8 md:p-12 rounded-3xl border border-slate-200/60 shadow-lg shadow-indigo-100/50 hover:shadow-xl transition-all duration-300">
                <div className="prose prose-lg prose-indigo max-w-none">
                    <ReactMarkdown components={detailedComponents}>
                        {detailedText}
                    </ReactMarkdown>
                </div>

                {/* Document Footer */}
                <div className="mt-16 pt-8 border-t border-slate-200/60 flex items-center justify-center">
                    <div className="h-1.5 w-16 bg-slate-200 rounded-full"></div>
                </div>
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  const subjectText = getContent('subject');

  return (
    <div className="w-full mt-8" dir={isUrdu ? 'rtl' : 'ltr'}>
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6">
        <span className="inline-flex items-center px-4 py-1.5 bg-gradient-to-r from-indigo-500 to-violet-500 text-white rounded-full text-sm font-bold tracking-wide uppercase shadow-md shadow-indigo-200">
          <span className={`w-2 h-2 bg-white rounded-full animate-pulse ${isUrdu ? 'ml-2' : 'mr-2'}`}></span>
          {subjectText}
        </span>
        <button 
          onClick={handleDownloadPDF}
          disabled={isGeneratingPdf}
          className="group flex items-center space-x-2 text-slate-500 hover:text-indigo-600 transition-colors text-sm font-medium mt-3 sm:mt-0 no-print"
        >
          <div className="p-2 bg-white rounded-full shadow-sm group-hover:shadow-md border border-slate-100 transition-all">
            {isGeneratingPdf ? <div className="animate-spin w-4 h-4 border-2 border-indigo-500 border-t-transparent rounded-full"></div> : <Download size={16} />}
          </div>
          <span>{isGeneratingPdf ? getT('generating') : getT('savePdf')}</span>
        </button>
      </div>

      {/* Tabs Navigation - Pill Style */}
      <div className="flex flex-wrap gap-2 mb-8 bg-slate-100/50 p-1.5 rounded-xl border border-slate-200/50 backdrop-blur-sm no-print">
        {tabs.map((tab) => {
             const isActive = activeTab === tab.id;
             return (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`
                  flex items-center space-x-2 px-4 py-2.5 rounded-lg transition-all duration-300 font-medium text-sm flex-1 sm:flex-none justify-center
                  ${isActive 
                    ? 'bg-white text-indigo-700 shadow-md transform scale-[1.02] ring-1 ring-black/5' 
                    : 'text-slate-500 hover:bg-white/60 hover:text-slate-700'
                  }
                `}
              >
                <span className={`transition-colors ${isActive ? 'text-indigo-600' : 'text-slate-400'}`}>
                    {tab.icon}
                </span>
                <span>{tab.label}</span>
              </button>
            );
        })}
      </div>

      {/* Content Area - Wrapped for ID targeting */}
      <div id="answer-content-export" className="min-h-[300px] p-2">
        {renderContent()}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { solveQuestion } from './services/geminiService';
import { HistoryItem, SolutionResponse, Language } from './types';
import { InputSection } from './components/InputSection';
import { AnswerSection } from './components/AnswerSection';
import { HistorySidebar } from './components/HistorySidebar';
import { Menu, GraduationCap, Github, Sparkles, AlertCircle, Globe, Feather } from 'lucide-react';

const App: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [currentQuestion, setCurrentQuestion] = useState<string>("");
  const [solution, setSolution] = useState<SolutionResponse | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [language, setLanguage] = useState<Language>('en');

  // Load history from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('sqs_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history", e);
      }
    }
  }, []);

  // Save history to local storage whenever it changes
  useEffect(() => {
    localStorage.setItem('sqs_history', JSON.stringify(history));
  }, [history]);

  const handleSolve = async (text: string, image: File | null, audio: Blob | null) => {
    setLoading(true);
    setError(null);
    setSolution(null);
    setCurrentQuestion(text || (audio ? "Audio Question" : "Image Question"));

    try {
      const result = await solveQuestion(text, image, audio, language);
      setSolution(result);

      // Add to history
      const newHistoryItem: HistoryItem = {
        id: Date.now().toString(),
        question: text || (audio ? "Audio Question" : (image ? "Image Question" : "Unknown Question")),
        timestamp: Date.now(),
        solution: result,
      };

      setHistory((prev) => [newHistoryItem, ...prev].slice(0, 50)); // Keep last 50
    } catch (err: any) {
      console.error(err);
      let errorMessage = language === 'ur' 
        ? "سوال حل کرنے میں ناکامی۔ براہ کرم دوبارہ کوشش کریں۔" 
        : "Failed to solve the question. Please try again.";

      if (err.message && err.message.includes("API key")) {
        errorMessage = language === 'ur' 
          ? "API کنفیگریشن کی خرابی: براہ کرم API کلید چیک کریں۔"
          : "API Configuration Error: Please check the API key.";
      }
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setSolution(item.solution);
    setCurrentQuestion(item.question);
    setError(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const isUrdu = language === 'ur';

  return (
    <div className={`min-h-screen relative overflow-hidden bg-slate-50 ${isUrdu ? 'font-[sans-serif]' : ''}`}>

      {/* Decorative background blobs - Enhanced */}
      <div className="fixed top-0 left-0 w-full h-full overflow-hidden -z-10 pointer-events-none">
        <div className="absolute top-[-20%] left-[-10%] w-[50%] h-[50%] bg-indigo-200/20 rounded-full blur-[100px] animate-pulse"></div>
        <div className="absolute bottom-[-20%] right-[-10%] w-[50%] h-[50%] bg-emerald-200/20 rounded-full blur-[100px] animate-pulse delay-700"></div>
        <div className="absolute top-[40%] left-[30%] w-[30%] h-[30%] bg-purple-200/20 rounded-full blur-[100px] animate-pulse delay-1000"></div>
      </div>

      {/* Navbar */}
      <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-xl border-b border-white/40 shadow-[0_4px_30px_rgba(0,0,0,0.03)] transition-all duration-300">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <button 
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              className="p-2.5 -ml-2 text-slate-600 hover:text-indigo-600 hover:bg-slate-100/80 rounded-xl transition-all duration-200 active:scale-95"
            >
              <Menu size={24} />
            </button>

            {/* Branding Section */}
            <div className="flex items-center space-x-3 group cursor-pointer" onClick={() => { setSolution(null); setError(null); }}>
              {/* Logo - Assuming logo.png is in public folder, fallback to icon */}
              <div className="relative h-12 w-12 flex-shrink-0">
                <div className="absolute inset-0 bg-gradient-to-tr from-green-500 to-emerald-600 rounded-xl blur-lg opacity-20 group-hover:opacity-40 transition-opacity"></div>
                <img 
                    src="/logo.png" 
                    alt="Logo" 
                    className="relative h-full w-full object-contain rounded-xl shadow-sm transform group-hover:scale-105 transition-transform duration-300"
                    onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        const fallback = document.getElementById('logo-fallback');
                        if (fallback) fallback.style.display = 'flex';
                    }}
                />
                <div id="logo-fallback" className="hidden absolute inset-0 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-xl items-center justify-center text-white shadow-md">
                     <span className="font-bold text-lg">AS</span>
                </div>
              </div>

              <div className="hidden sm:flex flex-col justify-center">
                 <h1 className="text-xl font-extrabold tracking-tight text-slate-900 leading-none group-hover:text-emerald-700 transition-colors">
                    Anwar Ali Sehar
                 </h1>
                 <span className="text-xs font-semibold text-transparent bg-clip-text bg-gradient-to-r from-emerald-600 to-teal-600 uppercase tracking-widest mt-1">
                    Student Question Solver
                 </span>
              </div>
            </div>
          </div>

          <div className="flex items-center space-x-3 sm:space-x-4">
            {/* Language Selector */}
            <div className="flex items-center bg-slate-100 p-1.5 rounded-xl border border-slate-200/50 shadow-inner">
                <button 
                    onClick={() => setLanguage('en')}
                    className={`px-3 py-1.5 text-xs font-bold rounded-lg transition-all duration-200 ${!isUrdu ? 'bg-white text-emerald-700 shadow-sm ring-1 ring-black/5' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    ENG
                </button>
                <button 
                    onClick={() => setLanguage('ur')}
                    className={`px-3 py-1.5 text-xs font-bold rounded-lg transition-all duration-200 ${isUrdu ? 'bg-white text-emerald-700 shadow-sm ring-1 ring-black/5' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    اردو
                </button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Layout */}
      <div className="flex">

        {/* Sidebar */}
        <HistorySidebar 
          history={history} 
          isOpen={isSidebarOpen} 
          onClose={() => setIsSidebarOpen(false)} 
          onSelect={handleSelectHistory}
          language={language}
        />

        {/* Content */}
        <main className={`flex-1 transition-all duration-300 ${isSidebarOpen ? 'md:ml-72' : ''} p-4 sm:p-6 lg:p-8 max-w-5xl mx-auto w-full`}>

          <div className="space-y-12 pb-20">
            {/* Hero Text */}
            {!solution && !loading && (
              <div className="text-center py-12 md:py-20 space-y-8 animate-fade-in-up">
                <div className="inline-flex items-center px-5 py-2.5 rounded-full bg-white border border-emerald-100 text-emerald-800 text-sm font-semibold mb-6 shadow-[0_2px_10px_rgba(0,0,0,0.05)] hover:shadow-md transition-shadow cursor-default">
                  <Sparkles size={16} className="mr-2 text-emerald-500" />
                  {isUrdu ? 'AI سے چلنے والا اسٹڈی ساتھی' : 'AI-Powered Study Companion by Anwar Ali Sehar'}
                </div>
                {isUrdu ? (
                     <h2 className="text-4xl md:text-6xl font-extrabold text-slate-900 tracking-tight leading-tight drop-shadow-sm" dir="rtl">
                     کسی بھی مضمون میں مہارت حاصل کریں <br/>
                     <span className="text-transparent bg-clip-text bg-gradient-to-r from-emerald-600 via-teal-500 to-cyan-600 animate-gradient-x">
                        صرف چند سیکنڈ میں۔
                     </span>
                   </h2>
                ) : (
                    <h2 className="text-4xl md:text-6xl font-extrabold text-slate-900 tracking-tight leading-[1.15] drop-shadow-sm">
                    Master any subject <br/>
                    <span className="text-transparent bg-clip-text bg-gradient-to-r from-emerald-600 via-teal-500 to-cyan-600 animate-gradient-x">
                        in seconds.
                    </span>
                    </h2>
                )}
                <p className={`text-xl text-slate-600 max-w-2xl mx-auto leading-relaxed px-4 ${isUrdu ? 'font-[sans-serif]' : ''}`} dir={isUrdu ? 'rtl' : 'ltr'}>
                  {isUrdu 
                    ? 'فوری بصری وضاحت حاصل کرنے کے لیے تصویر اپ لوڈ کریں، اپنی آواز ریکارڈ کریں، یا کوئی سوال ٹائپ کریں۔' 
                    : 'Upload a photo, record your voice, or type a question to get instant visual explanations.'}
                </p>
              </div>
            )}

            {/* Error Banner */}
            {error && (
              <div className="max-w-3xl mx-auto bg-red-50 border border-red-100 text-red-700 p-4 rounded-2xl flex items-center justify-center animate-fade-in-up shadow-sm">
