import React, { useRef, useState } from 'react';
import { Camera, Mic, Image as ImageIcon, X, StopCircle, Sparkles, ArrowRight } from 'lucide-react';
import { useAudioRecorder } from '../hooks/useAudioRecorder';
import { Language } from '../types';

interface InputSectionProps {
  onSolve: (text: string, image: File | null, audio: Blob | null) => void;
  isLoading: boolean;
  language: Language;
}

export const InputSection: React.FC<InputSectionProps> = ({ onSolve, isLoading, language }) => {
  const [text, setText] = useState('');
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const { isRecording, audioBlob, startRecording, stopRecording, clearAudio } = useAudioRecorder();
  const [isFocused, setIsFocused] = useState(false);

  const isUrdu = language === 'ur';
  const placeholder = isUrdu 
    ? "اپنا سوال یہاں لکھیں، یا آواز/کیمرہ استعمال کریں..." 
    : "Type your question here, or use voice/camera...";

  const solveText = isUrdu ? "حل کریں" : "Solve";
  const solvingText = isUrdu ? "...حل ہو رہا ہے" : "Solving...";
  const recordingText = isUrdu ? "رکارڈنگ ہو رہی ہے" : "Recording...";
  const imageAttachedText = isUrdu ? "تصویر منسلک ہے" : "Image Attached";
  const audioAttachedText = isUrdu ? "آواز ریکارڈ ہو گئی" : "Voice Recording Attached";

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedImage(e.target.files[0]);
    }
  };

  const removeImage = () => {
    setSelectedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!text && !selectedImage && !audioBlob) return;
    onSolve(text, selectedImage, audioBlob);
  };

  const handleContainerClick = (e: React.MouseEvent) => {
    // Prevent focusing if clicking on buttons/controls
    if ((e.target as HTMLElement).tagName === 'BUTTON' || (e.target as HTMLElement).closest('button')) {
      return;
    }
    textareaRef.current?.focus();
  };

  return (
    <div className="relative w-full max-w-3xl mx-auto group">
      {/* Glow Effect Layer */}
      <div 
        className={`absolute -inset-0.5 bg-gradient-to-r from-emerald-500 via-teal-500 to-indigo-500 rounded-2xl opacity-20 group-hover:opacity-40 transition duration-500 blur-sm ${isFocused ? 'opacity-60 blur-md' : ''}`}
      ></div>

      <div 
        dir={isUrdu ? 'rtl' : 'ltr'}
        className={`
        relative bg-white rounded-2xl p-6 w-full transition-all duration-300 cursor-text
        border border-slate-100/80
        ${isFocused ? 'shadow-2xl shadow-emerald-500/10' : 'shadow-xl shadow-slate-200/50'}
      `}>
        <form onSubmit={handleSubmit} className="space-y-4">

          {/* Text Input */}
          <div className="relative group">
            <textarea
              ref={textareaRef}
              value={text}
              onChange={(e) => setText(e.target.value)}
              onFocus={() => setIsFocused(true)}
              onBlur={() => setIsFocused(false)}
              placeholder={placeholder}
              className={`w-full p-2 text-lg bg-transparent border-0 focus:ring-0 text-slate-800 placeholder-slate-400 resize-none leading-relaxed selection:bg-emerald-100 ${isUrdu ? 'font-[sans-serif]' : ''}`}
              style={{ minHeight: '120px' }}
              disabled={isLoading}
            />
          </div>

          {/* Attachments Preview */}
          {(selectedImage || audioBlob) && (
              <div className="flex flex-wrap gap-3 animate-fade-in-up py-3 border-t border-slate-50">
                  {selectedImage && (
                      <div className="relative group inline-block">
                          <div className="flex items-center space-x-2 bg-indigo-50 px-3 py-2 rounded-xl border border-indigo-100/50 shadow-sm hover:shadow-md transition-shadow">
                              <div className="p-1 bg-white rounded-lg">
                                <ImageIcon size={16} className="text-indigo-600"/>
                              </div>
                              <span className="text-sm text-indigo-700 truncate max-w-[150px] font-medium">
                                {selectedImage.name || imageAttachedText}
                              </span>
                          </div>
                          <button 
                              type="button" 
                              onClick={(e) => { e.stopPropagation(); removeImage(); }}
                              className={`absolute -top-2 bg-white text-red-500 border border-red-100 rounded-full p-1 shadow-md hover:bg-red-50 transition-all transform hover:scale-110 ${isUrdu ? '-left-2' : '-right-2'}`}
                          >
                              <X size={12} />
                          </button>
                      </div>
                  )}
                  {audioBlob && (
                      <div className="relative group inline-block">
                          <div className="flex items-center space-x-2 bg-pink-50 px-3 py-2 rounded-xl border border-pink-100/50 shadow-sm hover:shadow-md transition-shadow">
                              <div className="p-1 bg-white rounded-lg animate-pulse">
                                <Mic size={16} className="text-pink-600"/>
                              </div>
                              <span className="text-sm text-pink-700 font-medium">{audioAttachedText}</span>
                          </div>
                          <button 
                              type="button" 
                              onClick={(e) => { e.stopPropagation(); clearAudio(); }}
                              className={`absolute -top-2 bg-white text-red-500 border border-red-100 rounded-full p-1 shadow-md hover:bg-red-50 transition-all transform hover:scale-110 ${isUrdu ? '-left-2' : '-right-2'}`}
                          >
                              <X size={12} />
                          </button>
                      </div>
                  )}
              </div>
          )}

          {/* Controls */}
          <div className="flex items-center justify-between pt-3 border-t border-slate-100 mt-2">
            <div className="flex items-center space-x-2">

              {/* Image Upload Button */}
              <button
                type="button"
                onClick={(e) => { e.stopPropagation(); fileInputRef.current?.click(); }}
                className="p-3 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50/50 rounded-xl transition-all duration-200 group relative overflow-hidden"
                title={isUrdu ? "تصویر اپ لوڈ کریں" : "Upload Image"}
                disabled={isLoading}
              >
                <div className="absolute inset-0 bg-emerald-100/50 transform scale-0 group-hover:scale-100 transition-transform duration-200 rounded-xl origin-center"></div>
                <Camera size={22} className="relative z-10" />
                <input
                  ref={fileInputRef}
                  type="file"
                  accept="image/*"
                  className="hidden"
                  onChange={handleImageUpload}
                />
              </button>

              {/* Voice Record Button */}
              <button
                type="button"
                onClick={(e) => { e.stopPropagation(); isRecording ? stopRecording() : startRecording(); }}
                className={`p-3 rounded-xl transition-all duration-300 flex items-center space-x-2 relative overflow-hidden ${
                  isRecording 
                    ? 'bg-red-50 text-red-600 ring-2 ring-red-100 animate-pulse' 
                    : 'text-slate-500 hover:text-pink-600 hover:bg-pink-50/50'
                }`}
                title={isRecording ? (isUrdu ? "ریکارڈنگ روکیں" : "Stop Recording") : (isUrdu ? "آواز ریکارڈ کریں" : "Record Voice")}
                disabled={isLoading}
              >
                <div className="relative z-10">
                    {isRecording ? <StopCircle size={22} /> : <Mic size={22} />}
                </div>
              </button>
            </div>

            {/* Submit Button */}
            <button
              type="submit"
              onClick={(e) => e.stopPropagation()}
              disabled={isLoading || (!text && !selectedImage && !audioBlob)}
              className={`
                flex items-center space-x-2 px-6 py-3 rounded-xl font-bold text-white transition-all duration-300 shadow-lg shadow-emerald-500/20
                ${isLoading || (!text && !selectedImage && !audioBlob)
                  ? 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none'
                  : 'bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-400 hover:to-teal-500 hover:shadow-emerald-500/40 hover:-translate-y-0.5 active:scale-95'
                }
              `}
            >
              {isLoading ? (
                <>
                  <svg className="animate-spin -ml-1 mr-2 h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  <span>{solvingText}</span>
                </>
              ) : (
                <>
                  <span className={`${isUrdu ? 'ml-2' : ''} hidden sm:inline`}>{solveText}</span>
                  {(!text && !selectedImage && !audioBlob) ? <Sparkles size={18} /> : (isUrdu ? <ArrowRight size={20} className="transform rotate-180" /> : <ArrowRight size={20} />)}
                </>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

