      ...bilingualStringSchema,
      description: "Mermaid.js diagram syntax. 'en' uses English labels, 'ur' uses Urdu labels. IMPORTANT: Enclose ALL node labels in double quotes.",
    },
    short: {
      ...bilingualStringSchema,
      description: "A very short 1-2 line summary.",
    },
    detailed: {
      ...bilingualStringSchema,
      description: "A comprehensive explanation with concepts, reasoning, and context using Markdown.",
    },
    handwrittenNotes: {
      ...bilingualStringSchema,
      description: "A neat, student-friendly solution layout mimicking a handwritten notebook. CRITICAL STYLE GUIDE: Use **bold** markdown for Headers, Questions (e.g., **Q1:**), and Key Actions (e.g., **Solve:**, **Answer:**). Use normal text for the math equations, explanations, and values. This allows rendering Red/Blue ink effect.",
    },
    easyNotes: {
      ...bilingualStringSchema,
      description: "Legacy field. Identical to handwrittenNotes.",
    },
    subject: {
      ...bilingualStringSchema,
      description: "The detected subject of the question (e.g., Physics / طبیعیات).",
    },
  },
  required: ["simple", "stepByStep", "visual", "short", "detailed", "handwrittenNotes", "subject"],
};

export const solveQuestion = async (
  text: string,
  imageFile: File | null,
  audioBlob: Blob | null,
  language: Language // Kept for API signature consistency, but we fetch both now
): Promise<SolutionResponse> => {
  const parts: any[] = [];

  const prompt = `
    You are an expert tutor. Analyze the question and provide a comprehensive answer in the requested JSON format.

    CRITICAL INSTRUCTION: You must provide **BOTH** English and Urdu versions for every single field in the response.

    For the 'Urdu' (ur) fields:
    - Write in proper Urdu script.
    - Maintain the same detailed Markdown formatting as the English version.
    - For 'visual' (Mermaid), translate the node labels to Urdu but keep IDs in ASCII.

    For 'handwrittenNotes' (Study Notes):
    - This section MUST mimic a neat handwritten solution on paper.
    - **Formatting Rule**: 
      - Use **Bold Text** for: Headings (e.g., **Q No 1:**), Step Names (e.g., **Step 1:**, **LCM:**), and Key Actions (e.g., **Cancel terms**, **Answer:**). These will be rendered in RED ink.
      - Use Normal Text for: The actual math equations, numbers, and variables. These will be rendered in BLUE ink.
    - Layout: Keep it vertical and spacious.
    - Example content:
      **Q No 1: Solve the equation**
      2x + 5 = 15
      **Subtract 5:**
      2x = 10
      **Divide by 2:**
      x = 5
      **Answer:** x = 5

    For the 'visual' field (Mermaid.js):
    1. Create a valid Mermaid.js diagram (flowchart or sequence).
    2. CRITICAL: Enclose all node labels in double quotes. Example: id["Label"] is correct.
    3. Do not include markdown code fences.

    Question: ${text}
  `;

  parts.push({ text: prompt });

  if (imageFile) {
    const base64Image = await fileToBase64(imageFile);
    parts.push({
      inlineData: {
        mimeType: imageFile.type,
        data: base64Image,
      },
    });
  }

  if (audioBlob) {
    const base64Audio = await blobToBase64(audioBlob);
    parts.push({
      inlineData: {
        mimeType: "audio/mp3",
        data: base64Audio,
      },
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        systemInstruction: `You are a helpful academic tutor. You always provide answers in both English and Urdu.`,
      },
    });

    const responseText = response.text;
    if (!responseText) throw new Error("No response from AI");

    return JSON.parse(responseText) as SolutionResponse;
  } catch (error) {
    console.error("Error solving question:", error);
    throw error;
  }
};

// Helper functions
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(",")[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      const base64 = result.split(",")[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

