  const downloadMenuRef = useRef<HTMLDivElement>(null);

  // Close download menu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (downloadMenuRef.current && !downloadMenuRef.current.contains(event.target as Node)) {
        setIsDownloadMenuOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Translations
  const t = {
    simple: { en: 'Simple', ur: 'آسان' },
    steps: { en: 'Steps', ur: 'مراحل' },
    studyNotes: { en: 'Study Notes', ur: 'اسٹڈی نوٹس' },
    easyNotes: { en: 'Easy Notes', ur: 'آسان نوٹس' },
    visual: { en: 'Visual', ur: 'تصویر' },
    short: { en: 'Short', ur: 'مختصر' },
    detailed: { en: 'Detailed', ur: 'تفصیلی' },
    simpleTitle: { en: 'Simple Explanation', ur: 'آسان وضاحت' },
    stepsTitle: { en: 'Step-by-Step Breakdown', ur: 'مرحلہ وار تفصیل' },
    studyNotesTitle: { en: 'Student Notebook (Formal)', ur: 'طالب علم نوٹ بک' },
    easyNotesTitle: { en: 'Simplified Easy Notes', ur: 'بچوں کے لیے آسان نوٹس' },
    visualTitle: { en: 'Visual Explanation', ur: 'بصری وضاحت' },
    shortTitle: { en: 'Quick Summary', ur: 'فوری خلاصہ' },
    detailedTitle: { en: 'Detailed Analysis', ur: 'تفصیلی تجزیہ' },
    savePdf: { en: 'Save as PDF', ur: 'پی ڈی ایف محفوظ کریں' },
    generating: { en: 'Generating PDF...', ur: 'پی ڈی ایف بن رہا ہے...' },
    downloadOptions: { en: 'Download Options', ur: 'ڈاؤن لوڈ کے اختیارات' },
    downloadJpg: { en: 'Download JPG', ur: 'JPG ڈاؤن لوڈ' },
    downloadPdf: { en: 'Download PDF', ur: 'PDF ڈاؤن لوڈ' },
    systemDiagram: { en: 'System Diagram', ur: 'سسٹم ڈایاگرام' },
    aiGenerated: { en: 'AI Generated Visualization', ur: 'AI کی تیار کردہ تصویر' },
    diagramHelp: { en: 'Pan to explore. Diagrams are automatically generated.', ur: 'تصویر کو گھسیٹ کر دیکھیں۔ تصاویر خودکار طور پر بنتی ہیں۔' },
    copy: { en: 'Copy', ur: 'کاپی کریں' },
    copied: { en: 'Copied!', ur: 'کاپی ہو گیا!' }
  };

  const getT = (key: keyof typeof t) => t[key][language];

  // Helper to safely get content based on language
  const getContent = (field: keyof SolutionResponse) => {
    // Check if the field is bilingual object (has 'en' and 'ur') or fallback for old history
    const data = solution[field] as any;
    if (typeof data === 'string') return data; // Old history format
    return data[language] || data['en']; // New bilingual format
  };

  const handleCopy = (text: string, sectionId: string) => {
    navigator.clipboard.writeText(text);
    setCopiedSection(sectionId);
    setTimeout(() => setCopiedSection(null), 2000);
  };

  const CopyButton = ({ text, id }: { text: string, id: string }) => (
    <button 
      onClick={() => handleCopy(text, id)}
      className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all ml-2"
      title={getT('copy')}
    >
      {copiedSection === id ? <Check size={18} className="text-green-500" /> : <Copy size={18} />}
    </button>
  );

  const tabs = [
    { id: AnswerMode.SIMPLE, label: getT('simple'), icon: <BookOpen size={18} />, color: 'bg-blue-100 text-blue-700' },
    { id: AnswerMode.EASY_NOTES, label: getT('easyNotes'), icon: <Feather size={18} />, color: 'bg-lime-100 text-lime-700' },
    { id: AnswerMode.HANDWRITTEN, label: getT('studyNotes'), icon: <Notebook size={18} />, color: 'bg-amber-100 text-amber-700' },
    { id: AnswerMode.STEP_BY_STEP, label: getT('steps'), icon: <List size={18} />, color: 'bg-emerald-100 text-emerald-700' },
    { id: AnswerMode.VISUAL, label: getT('visual'), icon: <ImageIcon size={18} />, color: 'bg-violet-100 text-violet-700' },
    { id: AnswerMode.SHORT, label: getT('short'), icon: <Zap size={18} />, color: 'bg-orange-100 text-orange-700' },
    { id: AnswerMode.DETAILED, label: getT('detailed'), icon: <FileText size={18} />, color: 'bg-indigo-100 text-indigo-700' },
  ];

  const handleDownloadPDF = async () => {
    setIsGeneratingPdf(true);
    const element = document.getElementById('answer-content-export');

    if (element && window.html2pdf) {
      const opt = {
        margin: [0.5, 0.5],
        filename: `${getContent('subject').replace(/\s+/g, '_')}_Solution.pdf`,
        image: { type: 'jpeg', quality: 0.98 },
        html2canvas: { scale: 2, useCORS: true },
        jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
      };

      try {
        await window.html2pdf().set(opt).from(element).save();
      } catch (e) {
        console.error("PDF generation failed", e);
        window.print();
      }
    } else {
       window.print();
    }
    setIsGeneratingPdf(false);
  };

  const handleZoom = (direction: 'in' | 'out') => {
    setZoomLevel(prev => {
        const newZoom = direction === 'in' ? prev + 0.25 : prev - 0.25;
        return Math.min(Math.max(newZoom, 0.5), 4);
    });
  };

  const handleResetZoom = () => {
    setZoomLevel(1);
    setPan({ x: 0, y: 0 });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    dragStartRef.current = { x: e.clientX - pan.x, y: e.clientY - pan.y };
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (isDragging) {
      e.preventDefault();
      setPan({
        x: e.clientX - dragStartRef.current.x,
        y: e.clientY - dragStartRef.current.y
      });
    }
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const handleDownloadJPG = () => {
    const svg = visualContainerRef.current?.querySelector('svg');
    if (svg) {
        // High resolution scale
        const scale = 3;

        // Get strict dimensions
        const svgSize = svg.getBoundingClientRect();
        const width = svgSize.width;
        const height = svgSize.height;

        const canvas = document.createElement('canvas');
        canvas.width = width * scale;
        canvas.height = height * scale;
        const ctx = canvas.getContext('2d');

        if (!ctx) return;

        // Create a standalone SVG string
        const serializer = new XMLSerializer();
        let svgData = serializer.serializeToString(svg);

        // Ensure namespace is present (crucial for standalone rendering)
        if (!svgData.match(/^<svg[^>]+xmlns="http\:\/\/www\.w3\.org\/2000\/svg"/)) {
            svgData = svgData.replace(/^<svg/, '<svg xmlns="http://www.w3.org/2000/svg"');
        }

        const img = new Image();
        img.crossOrigin = "anonymous";

        img.onload = () => {
            // Fill white background (JPG doesn't support transparency)
            ctx.fillStyle = "#ffffff";
            ctx.fillRect(0, 0, canvas.width, canvas.height);
            ctx.drawImage(img, 0, 0, canvas.width, canvas.height);

            try {
                const jpgUrl = canvas.toDataURL("image/jpeg", 0.95);
                const link = document.createElement('a');
                link.href = jpgUrl;
                link.download = `${getContent('subject')}_Diagram.jpg`;
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
            } catch (e) {
                console.error("JPG export failed", e);
                alert("Image export failed due to browser security settings.");
            }
            URL.revokeObjectURL(url);
            setIsDownloadMenuOpen(false);
        };

        img.onerror = (e) => {
             console.error("Image loading failed for export", e);
             alert("Could not load image for export.");
             URL.revokeObjectURL(url);
             setIsDownloadMenuOpen(false);
        };

        const svgBlob = new Blob([svgData], {type: 'image/svg+xml;charset=utf-8'});
        const url = URL.createObjectURL(svgBlob);
        img.src = url;
    }
  };

  const handleDownloadDiagramPDF = () => {
    const element = visualContainerRef.current?.querySelector('svg');

    if (element && window.html2pdf) {
         const opt = {
            margin: 0.5,
            filename: `${getContent('subject')}_Diagram.pdf`,
            image: { type: 'jpeg', quality: 0.98 },
            html2canvas: { scale: 2 },
            jsPDF: { unit: 'in', format: 'letter', orientation: 'landscape' }
        };

        window.html2pdf().set(opt).from(element).save().then(() => {
            setIsDownloadMenuOpen(false);
        });
    }
  };

  // --- Components for Step-by-Step View ---
  const stepsComponents: any = {
    // Style numbered lists to be clean and spacious
    ol: ({node, ...props}: any) => <ol className="space-y-4 my-6 list-none p-0" {...props} />,
    ul: ({node, ...props}: any) => <ul className={`space-y-3 my-4 list-disc ${isUrdu ? 'pr-5' : 'pl-5'}`} {...props} />,

    // Each step is a "card"
    li: ({node, ...props}: any) => {
        return (
            <li className="relative bg-white p-5 rounded-xl border border-emerald-100/50 shadow-[0_2px_8px_-2px_rgba(0,0,0,0.05)] hover:shadow-md transition-all text-lg leading-relaxed text-slate-700">
                {props.children}
            </li>
        );
    },
    h3: ({node, ...props}: any) => <h3 className="text-xl font-bold text-emerald-800 mb-3 mt-1" {...props} />,
    strong: ({node, ...props}: any) => <strong className="font-bold text-emerald-900 bg-emerald-100/50 px-1.5 py-0.5 rounded-md" {...props} />,
    p: ({node, ...props}: any) => <p className="mb-2 last:mb-0" {...props} />,
  };

  // --- Components for Realistic Handwritten Notes (Study Notes - Red/Blue Ink) ---
  const studyNotesComponents: any = {
    p: ({node, ...props}: any) => (
      <p className="mb-0 text-[#1e40af] text-[22px] font-medium leading-[40px] font-handwriting tracking-wide" {...props} />
    ),
    strong: ({node, ...props}: any) => (
      <strong className="text-[#dc2626] font-bold text-[24px] font-handwriting" {...props} />
    ),
