  const handleDownloadJPG = () => {
    const svg = visualContainerRef.current?.querySelector('svg');
    if (svg) {
        // High resolution scale
        const scale = 3;

        // Get strict dimensions
        const svgSize = svg.getBoundingClientRect();
        const width = svgSize.width;
        const height = svgSize.height;

        const canvas = document.createElement('canvas');
        canvas.width = width * scale;
        canvas.height = height * scale;
        const ctx = canvas.getContext('2d');

        if (!ctx) return;

        // Create a standalone SVG string
        const serializer = new XMLSerializer();
        let svgData = serializer.serializeToString(svg);

        // Ensure namespace is present (crucial for standalone rendering)
        if (!svgData.match(/^<svg[^>]+xmlns="http\:\/\/www\.w3\.org\/2000\/svg"/)) {
            svgData = svgData.replace(/^<svg/, '<svg xmlns="http://www.w3.org/2000/svg"');
        }

        const img = new Image();
        img.crossOrigin = "anonymous";

        img.onload = () => {
            // Fill white background (JPG doesn't support transparency)
            ctx.fillStyle = "#ffffff";
            ctx.fillRect(0, 0, canvas.width, canvas.height);
            ctx.drawImage(img, 0, 0, canvas.width, canvas.height);

            try {
                const jpgUrl = canvas.toDataURL("image/jpeg", 0.95);
                const link = document.createElement('a');
                link.href = jpgUrl;
                link.download = `${getContent('subject')}_Diagram.jpg`;
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
            } catch (e) {
                console.error("JPG export failed", e);
                alert("Image export failed due to browser security settings.");
            }
            URL.revokeObjectURL(url);
            setIsDownloadMenuOpen(false);
        };

        img.onerror = (e) => {
             console.error("Image loading failed for export", e);
             alert("Could not load image for export.");
             URL.revokeObjectURL(url);
             setIsDownloadMenuOpen(false);
        };

        const svgBlob = new Blob([svgData], {type: 'image/svg+xml;charset=utf-8'});
        const url = URL.createObjectURL(svgBlob);
        img.src = url;
    }
  };

